import CloseIcon from '@mui/icons-material/Close';
import FavoriteRoundedIcon from '@mui/icons-material/FavoriteRounded';
import { Box, Divider, Drawer, IconButton, List, Stack, Typography } from '@mui/material';
import React from 'react';
import WishItem from './Wishitem';

export const Wishlist = (props) => {
    const { wishOpen, closeWish = Function.prototype, wishList = [], removeFromWishList } = props;

    return (
        <Drawer
            anchor="right"
            open={wishOpen}
            onClose={closeWish}
            PaperProps={{
                sx: {
                    width: { xs: '100%', sm: '450px' },
                    backgroundColor: '#171A20',
                    backgroundImage: 'none',
                    borderLeft: '1px solid rgba(255, 255, 255, 0.06)',
                    p: 0,
                }
            }}
        >
            <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
                <Box sx={{ p: 3, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <Stack direction="row" spacing={2} alignItems="center">
                        <FavoriteRoundedIcon sx={{ color: 'primary.main' }} />
                        <Typography variant="h6" sx={{ fontWeight: 800, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                            Wishlist
                        </Typography>
                    </Stack>
                    <IconButton onClick={closeWish} sx={{ color: 'text.secondary', '&:hover': { color: 'white' } }}>
                        <CloseIcon />
                    </IconButton>
                </Box>

                <Divider sx={{ opacity: 0.1 }} />

                <Box sx={{ flexGrow: 1, overflowY: 'auto', p: 3 }}>
                    {!wishList.length ? (
                        <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 2, opacity: 0.5 }}>
                            <FavoriteRoundedIcon sx={{ fontSize: '3rem' }} />
                            <Typography variant="body1">Your wishlist is empty</Typography>
                        </Box>
                    ) : (
                        <List disablePadding>
                            {wishList.map((item) => (
                                <WishItem 
                                    key={item.id} 
                                    removeFromWishList={removeFromWishList} 
                                    {...item} 
                                />
                            ))}
                        </List>
                    )}
                </Box>
            </Box>
        </Drawer>
    )
}

export default Wishlist;
